        /* Inter Font Faces */
        @font-face {
            font-family: 'Inter';
            src: url('chrome-extension://agpbjhhcmoanaljagpoheldgjhclepdj/libs/inter/fonts/Inter[wght].woff2') format('woff2-variations');
            font-weight: 100 900;
            font-style: normal;
            font-display: swap;
        }
        
        @font-face {
            font-family: 'Inter';
            src: url('chrome-extension://agpbjhhcmoanaljagpoheldgjhclepdj/libs/inter/fonts/Inter-Italic[wght].woff2') format('woff2-variations');
            font-weight: 100 900;
            font-style: italic;
            font-display: swap;
        }

        /* Floating Button Core Styles */
        #tm-floating-button {
            position: fixed;
            bottom: 25%;
            right: 0;
            z-index: 9999;
            width: 38px;
            height: 38px;
            background: transparent;
            border-radius: 50px 0 0 50px;
            cursor: pointer;
            overflow: visible;
            transition: right 0.3s ease, left 0.3s ease, border-radius 0.3s ease;
            margin: 0;
            padding: 0;
            border: none;
            outline: none;
            box-sizing: border-box;
        }

        #tm-floating-button.left-side {
            right: auto;
            left: 0;
            border-radius: 0 50px 50px 0;
        }

        #tm-floating-button.dragging {
            border-radius: 50px;
        }

        /* Collapsed State */
        #tm-floating-button .tm-collapsed-state {
            position: absolute;
            top: 0;
            right: 0;
            display: flex;
            align-items: center;
            justify-content: center;
            width: 38px;
            height: 38px;
            background: transparent;
            border-radius: 50px 0 0 50px;
            border: 0.2px solid #DADADA;
            border-right: none;
            z-index: 1;
            opacity: 1;
            transition: opacity 0.2s ease, border-radius 0.3s ease;
            margin: 0;
            padding: 0;
            box-sizing: border-box;
        }

        #tm-floating-button.left-side .tm-collapsed-state {
            right: auto;
            left: 0;
            border-radius: 0 50px 50px 0;
            border: 0.2px solid #DADADA;
            border-left: none;
        }

        #tm-floating-button.dragging .tm-collapsed-state {
            border-radius: 50px;
            border: 0.2px solid #DADADA;
        }

        /* Hide status text during drag */
        #tm-floating-button.dragging .tm-status-text {
            display: none !important;
        }

        /* Collapsed State - Remove !important from display to allow JavaScript control */
        #tm-floating-button.expanded .tm-collapsed-state {
            display: none;
        }

        /* Icons - Remove !important from display to allow JavaScript control */
        #tm-floating-button .tm-icon {
            width: 24px;
            height: 24px;
            object-fit: contain;
            margin: 0;
            padding: 0;
            border: none;
        }

        /* Expanded State - Remove !important from JavaScript-controlled properties */
        #tm-floating-button .tm-expanded-state {
            position: absolute;
            top: 0;
            right: 0;
            width: 219px;
            height: auto;
            background: rgba(26, 26, 26, 0.80);
            backdrop-filter: blur(6px);
            -webkit-backdrop-filter: blur(6px);
            border: 1px solid white;
            border-right: none;
            border-radius: 24px 0 0 24px;
            box-shadow: 0 16px 26px -8px rgba(18, 43, 96, 0.18), 0 1px 0 0 rgba(56, 105, 212, 0.12);
            display: flex;
            flex-direction: column;
            padding-bottom: 10px;
            overflow: hidden;
            transform: translateX(169px);
            opacity: 0;
            pointer-events: none;
            transition: transform 0.3s cubic-bezier(0.4, 0, 0.2, 1), opacity 0.3s cubic-bezier(0.4, 0, 0.2, 1), border-radius 0.3s ease;
            z-index: 2;
            margin: 0;
            padding-top: 0;
            padding-left: 0;
            padding-right: 0;
            box-sizing: border-box;
        }

        #tm-floating-button.left-side .tm-expanded-state {
            right: auto;
            left: 0;
            border-right: 1px solid white;
            border-left: none;
            border-radius: 0 24px 24px 0;
            transform: translateX(-169px);
        }

        #tm-floating-button.expanded .tm-expanded-state {
            transform: translateX(0);
            opacity: 1;
            pointer-events: auto;
            z-index: 2;
        }

        /* Panel Header */
        #tm-floating-button .tm-panel-header {
            display: flex;
            align-items: center;
            justify-content: space-between;
            padding: 8px;
            background: transparent;
            border-radius: 24px 0 0 0;
            flex-shrink: 0;
            margin: 0;
            border: none;
            box-sizing: border-box;
        }

        #tm-floating-button.left-side .tm-panel-header {
            flex-direction: row-reverse;
            border-radius: 0 24px 0 0;
        }

        /* Action Buttons */
        #tm-floating-button .tm-panel-actions {
            display: flex;
            flex-direction: column;
            gap: 12px;
            padding: 12px 8px;
            flex-shrink: 0;
            margin: 0;
            border: none;
            box-sizing: border-box;
        }

        #tm-floating-button .tm-action-btn {
            border-radius: 24px;
            border: 0.8px solid rgba(255, 255, 255, 0.4);
            background: transparent;
            display: flex;
            align-items: center;
            justify-content: flex-start;
            gap: 8px;
            padding: 12px;
            cursor: pointer;
            font-family: 'Inter';
            font-size: 14px;
            font-style: normal;
            font-weight: 500;
            letter-spacing: -0.2px;
            line-height: 100%;
            transition: all 0.2s ease;
            flex-shrink: 0;
            color: #FFF;
            box-shadow: 0 4px 10px 0 rgba(0, 0, 0, 0.05);
            margin: 0;
            outline: none;
            box-sizing: border-box;
        }

        #tm-floating-button .tm-action-btn:hover {
            background: rgba(66, 66, 66, 0.4);
        }

        #tm-floating-button .tm-favicon {
            width: 20px;
            height: 20px;
            object-fit: contain;
            flex-shrink: 0;
        }

        /* Voice Typing Button - shortcut on right */
        #tm-floating-button .tm-action-voice {
            justify-content: space-between;
        }

        /* Voice Typing Transcribing State */
        #tm-floating-button .tm-voice-transcribing-state {
            display: none;
            align-items: center;
            gap: 8px;
        }

        #tm-floating-button .tm-transcribing-label {
            font-family: 'Inter', sans-serif;
            font-weight: 500;
            font-size: 14px;
            color: white;
            white-space: nowrap;
        }

        /* Animated dots keyframes */
        @keyframes tm-ellipsis {
            0%, 100% {
                opacity: 0;
            }
            50% {
                opacity: 1;
            }
        }

        #tm-floating-button .tm-stop-icon {
            flex-shrink: 0;
        }

        #tm-floating-button .tm-microphone-icon {
            width: 20px;
            height: 20px;
            flex-shrink: 0;
        }

        /* Options */
        #tm-floating-button .tm-option-item {
            padding: 8px 16px;
            font-family: 'Inter';
            font-weight: 500;
            font-size: 12px;
            color: white;
            cursor: pointer;
            transition: background-color 0.15s ease;
            margin: 0;
            border: none;
            outline: none;
            background: transparent;
            box-sizing: border-box;
        }

        #tm-floating-button .tm-option-item:hover {
            background-color: rgba(66, 66, 66, 0.4);
        }

        /* Status Text */
        #tm-floating-button .tm-status-text {
            position: absolute;
            right: calc(100% + 12px);
            left: auto;
            top: 6px;
            background: #17171b;
            color: white;
            font-family: 'Inter';
            font-size: 12px;
            font-weight: 400;
            line-height: 1.4;
            text-align: center;
            padding: 6px 12px;
            border-radius: 8px;
            white-space: nowrap;
            z-index: 1001;
            pointer-events: none;
            margin: 0;
            border: none;
            outline: none;
            box-sizing: border-box;
        }

        /* Status Text - position on right when button is on left side */
        #tm-floating-button.left-side .tm-status-text {
            right: auto;
            left: calc(100% + 12px);
        }

        /* Other UI Elements */
        #tm-floating-button .tm-logo {
            width: 28px;
            height: 28px;
            border-radius: 38.236px;
            object-fit: contain;
        }

        /* Header Icon Container */
        #tm-floating-button .tm-header-icon-container {
            width: 28px;
            height: 28px;
            position: relative;
        }

        #tm-floating-button .tm-header-icon-container .tm-logo {
            position: absolute;
            top: 0;
            left: 0;
        }

        /* Expanded state bar animation */
        #tm-floating-button .tm-expanded-voice-mode-icon .tm-expanded-bar {
            transform-origin: center center;
        }

        /* CSS bar bounce animation (same as sidepanel sound-visualizer) */
        @keyframes tm-bar-bounce {
            0%, 100% { transform: scaleY(0.5); }
            50% { transform: scaleY(1); }
        }

        #tm-floating-button .tm-bar-animating .tm-expanded-bar,
        #tm-floating-button .tm-bar-animating rect {
            animation: tm-bar-bounce 1.2s ease-in-out infinite;
            transform-origin: center center;
        }

        #tm-floating-button .tm-bar-animating .tm-expanded-bar:nth-child(1),
        #tm-floating-button .tm-bar-animating rect:nth-child(1) { animation-delay: 0.5s; }
        #tm-floating-button .tm-bar-animating .tm-expanded-bar:nth-child(2),
        #tm-floating-button .tm-bar-animating rect:nth-child(2) { animation-delay: 0.1s; }
        #tm-floating-button .tm-bar-animating .tm-expanded-bar:nth-child(3),
        #tm-floating-button .tm-bar-animating rect:nth-child(3) { animation-delay: 0.9s; }

        #tm-floating-button .tm-keyboard-shortcut {
            background: #FFFFFF;
            color: #0B4F75;
            font-size: 12px;
            font-weight: 500;
            padding: 4px 6px;
            border-radius: 16px;
            white-space: nowrap;
            letter-spacing: -0.2px;
            flex-shrink: 0;
        }

        #tm-floating-button .tm-panel-divider {
            height: 0.8px;
            background: rgba(255, 255, 255, 0.2);
            width: 100%;
            flex-shrink: 0;
        }

        #tm-floating-button .tm-panel-options {
            display: flex;
            flex-direction: column;
            gap: 6px;
            flex-shrink: 0;
        }

        /* ========== EXPAND UP STYLES (when button is near bottom of screen) ========== */
        
        /* Expanded state - anchor to bottom of button, expand upward */
        #tm-floating-button.expand-up .tm-expanded-state {
            top: auto;
            bottom: 0;
            flex-direction: column-reverse;
            padding-top: 12px;
            padding-bottom: 0;
        }

        /* Collapsed state - anchor to bottom when expand-up */
        #tm-floating-button.expand-up .tm-collapsed-state {
            top: auto;
            bottom: 0;
        }

        /* Border radius adjustments for expand-up (right side) */
        #tm-floating-button.expand-up .tm-expanded-state {
            border-radius: 24px 0 0 24px;
        }

        #tm-floating-button.expand-up.left-side .tm-expanded-state {
            border-radius: 0 24px 24px 0;
        }

        /* Panel header - at bottom in expand-up mode (due to column-reverse, it appears at bottom) */
        #tm-floating-button.expand-up .tm-panel-header {
            border-radius: 0;
        }

        #tm-floating-button.expand-up.left-side .tm-panel-header {
            border-radius: 0;
        }

        /* Panel options - appears at top in expand-up mode (due to column-reverse) */
        #tm-floating-button.expand-up .tm-panel-options {
            padding-bottom: 8px;
        }
    </style><style id="tm-notification-styles">
