5L5.5 5.5" stroke="currentColor" stroke-width="1.2" stroke-linecap="round" stroke-linejoin="round"></path></svg></svg>Submissions</button></div><div class="chakra-tabs__tab-panels css-8atqhb"><div tabindex="0" role="tabpanel" aria-labelledby="tabs-:R5lbj79f6:--tab-0" id="tabs-:R5lbj79f6:--tabpanel-0" class="chakra-tabs__tab-panel css-15zvaxn" hidden=""><div class="css-15n7aez"></div><div class="Markdown_reactMarkdown__X0aZ_"><p>Given a table of Facebook posts, for each user who posted at least twice in 2021, write a query to find the number of days between each user’s first post of the year and last post of the year in the year 2021. Output the user and number of the days between each user's first and last post.</p>
<p>p.s. If you've read the <a target="_blank" rel="noopener noreferrer" href="https://www.amazon.com/dp/0578973839?ref_=pe_3052080_397514860">Ace the Data Science Interview</a> and liked it, consider writing us a review?</p>
<h3 class="chakra-heading css-ajgoem" level="3" node="[object Object]"><code>posts</code> Table:</h3>
<div style="overflow-x:auto;margin-bottom:10px"><table><thead><tr><th style="text-align:left">Column Name</th><th style="text-align:left">Type</th></tr></thead><tbody><tr><td style="text-align:left">user_id</td><td style="text-align:left">integer</td></tr><tr><td style="text-align:left">post_id</td><td style="text-align:left">integer</td></tr><tr><td style="text-align:left">post_content</td><td style="text-align:left">text</td></tr><tr><td style="text-align:left">post_date</td><td style="text-align:left">timestamp</td></tr></tbody></table></div>
<h3 class="chakra-heading css-ajgoem" level="3" node="[object Object]"><code>posts</code> Example Input:</h3>
<div style="overflow-x:auto;margin-bottom:10px"><table><thead><tr><th style="text-align:left">user_id</th><th style="text-align:left">post_id</th><th style="text-align:left">post_content</th><th style="text-align:left">post_date</th></tr></thead><tbody><tr><td style="text-align:left">151652</td><td style="text-align:left">599415</td><td style="text-align:left">Need a hug</td><td style="text-align:left">07/10/2021 12:00:00</td></tr><tr><td style="text-align:left">661093</td><td style="text-align:left">624356</td><td style="text-align:left">Bed. Class 8-12. Work 12-3. Gym 3-5 or 6. Then class 6-10. Another day that's gonna fly by. I miss my girlfriend</td><td style="text-align:left">07/29/2021 13:00:00</td></tr><tr><td style="text-align:left">004239</td><td style="text-align:left">784254</td><td style="text-align:left">Happy 4th of July!</td><td style="text-align:left">07/04/2021 11:00:00</td></tr><tr><td style="text-align:left">661093</td><td style="text-align:left">442560</td><td style="text-align:left">Just going to cry myself to sleep after watching Marley and Me.</td><td style="text-align:left">07/08/2021 14:00:00</td></tr><tr><td style="text-align:left">151652</td><td style="text-align:left">111766</td><td style="text-align:left">I'm so done with covid - need travelling ASAP!</td><td style="text-align:left">07/12/2021 19:00:00</td></tr></tbody></table></div>
<h3 class="chakra-heading css-ajgoem" level="3" node="[object Object]">Example Output:</h3>
<div style="overflow-x:auto;margin-bottom:10px"><table><thead><tr><th style="text-align:left">user_id</th><th style="text-align:left">days_between</th></tr></thead><tbody><tr><td style="text-align:left">151652</td><td style="text-align:left">2</td></tr><tr><td style="text-align:left">661093</td><td style="text-align:left">21</td></tr></tbody></table></div>
<p>The dataset you are querying against may have different input &amp; output - <strong>this is just an example</strong>!</p></div><div class="chakra-offset-slide" style="opacity: 1; transform: none;"><div class="css-j7qwjs"><div class="css-70qvj9"><hr aria-orientation="horizontal" class="chakra-divider css-svjswr"><p class="chakra-text css-1h4rdo3" style="white-space: nowrap;">Hint #1</p><hr aria-orientation="horizontal" class="chakra-divider css-svjswr"></div><div class="Markdown_reactMarkdown__X0aZ_"><p>Do you know how to obtain the last and first post per user?
Try using the <code>MIN</code> and <code>MAX</code> functions, and then substract one from another.</p>
<p>Find more info about <a target="_blank" rel="noopener noreferrer" href="https://www.postgresqltutorial.com/postgresql-aggregate-functions/postgresql-max-function/">MAX</a> and <a target="_blank" rel="noopener noreferrer" href="https://www.postgresqltutorial.com/postgresql-aggregate-functions/postgresql-min-function/">MIN</a> functions.</p></div></div></div><div class="chakra-offset-slide" style="opacity: 1; transform: none;"><div class="css-j7qwjs"><div class="css-70qvj9"><hr aria-orientation="horizontal" class="chakra-divider css-svjswr"><p class="chakra-text css-1h4rdo3" style="white-space: nowrap;">Hint #2</p><hr aria-orientation="horizontal" class="chakra-divider css-svjswr"></div><div class="Markdown_reactMarkdown__X0aZ_"><p>Here you go, fill in the the remaining columns yourself!</p>
<pre><div style="text-align: left; white-space: pre; word-spacing: normal; word-break: normal; overflow-wrap: normal; color: rgb(144, 164, 174); background: rgb(250, 250, 250); font-family: &quot;Roboto Mono&quot;, monospace; font-size: 1em; line-height: 1.5em; tab-size: 4; hyphens: none; overflow: auto; position: relative; margin: 0.5em 0px; padding: 1.25em 1em;"><code style="white-space: pre; background: inherit;"><span class="token token" style="color: rgb(124, 77, 255);">SELECT</span><span>
</span><span>  fill_in_column</span><span class="token token" style="color: rgb(57, 173, 181);">,</span><span>
</span><span>  </span><span class="token token" style="color: rgb(124, 77, 255);">MAX</span><span class="token token" style="color: rgb(57, 173, 181);">(</span><span>post_date::</span><span class="token token" style="color: rgb(124, 77, 255);">DATE</span><span class="token token" style="color: rgb(57, 173, 181);">)</span><span> </span><span class="token token" style="color: rgb(57, 173, 181);">-</span><span> </span><span class="token token" style="color: rgb(124, 77, 255);">MIN</span><span class="token token" style="color: rgb(57, 173, 181);">(</span><span>post_date::</span><span class="token token" style="color: rgb(124, 77, 255);">DATE</span><span class="token token" style="color: rgb(57, 173, 181);">)</span><span>
</span><span></span><span class="token token" style="color: rgb(124, 77, 255);">FROM</span><span> posts
</span><span></span><span class="token token" style="color: rgb(124, 77, 255);">GROUP</span><span> </span><span class="token token" style="color: rgb(124, 77, 255);">BY</span><span> 
</span>  fill_in_column</code></div></pre>
<p>Did you notice that we were asked to find the results only for the users who have posted twice during the year 2021? Let's break this down.</p>
<p>First, <code>DATE_PART</code> is a useful function to extract a part of a date (e.g. day, month, year) from a given input date. Read more <a target="_blank" rel="noopener noreferrer" href="https://www.postgresqltutorial.com/postgresql-date-functions/postgresql-date_part/">here</a></p>
<p>Check the code snippet below and replace 'part' with the desired granularity.</p>
<pre><div style="text-align: left; white-space: pre; word-spacing: normal; word-break: normal; overflow-wrap: normal; color: rgb(144, 164, 174); background: rgb(250, 250, 250); font-family: &quot;Roboto Mono&quot;, monospace; font-size: 1em; line-height: 1.5em; tab-size: 4; hyphens: none; overflow: auto; position: relative; margin: 0.5em 0px; padding: 1.25em 1em;"><code style="white-space: pre; background: inherit;"><span>DATE_PART</span><span class="token token" style="color: rgb(57, 173, 181);">(</span><span class="token token" style="color: rgb(246, 164, 52);">'part'</span><span class="token token" style="color: rgb(57, 173, 181);">,</span><span> post_date</span><span class="token token" style="color: rgb(57, 173, 181);">)</span></code></div></pre>
<p><em>Psst, note that we can't use DATEDIFF and TIMESTAMPDIFF functions as these are MySQL's functions.</em></p></div></div></div><div class="chakra-offset-slide" style="opacity: 1; transform: none;"><div class="css-j7qwjs"><div class="css-70qvj9"><hr aria-orientation="horizontal" class="chakra-divider css-svjswr"><p class="chakra-text css-1h4rdo3" style="white-space: nowrap;">Hint #3</p><hr aria-orientation="horizontal" class="chakra-divider css-svjswr"></div><div class="Markdown_reactMarkdown__X0aZ_"><p>Here you go - copy-paste it, and try it out yourself. However, I have still left a small task for you.
To focus on the users who have posted more than once, you can <code>COUNT</code> the number of posts and exclude users with 1 post only.  What do you think, should you use <code>HAVING</code> or <code>WHERE</code> for this?</p>
<p>To offer some background, <code>HAVING</code> clause applies to the group as whole, while <code>WHERE</code> applies to individual rows.</p>
<pre><div style="text-align: left; white-space: pre; word-spacing: normal; word-break: normal; overflow-wrap: normal; color: rgb(144, 164, 174); background: rgb(250, 250, 250); font-family: &quot;Roboto Mono&quot;, monospace; font-size: 1em; line-height: 1.5em; tab-size: 4; hyphens: none; overflow: auto; position: relative; margin: 0.5em 0px; padding: 1.25em 1em;"><code style="white-space: pre; background: inherit;"><span class="token token" style="color: rgb(124, 77, 255);">SELECT</span><span> 
</span><span>	user_id</span><span class="token token" style="color: rgb(57, 173, 181);">,</span><span> 
</span><span>    </span><span class="token token" style="color: rgb(124, 77, 255);">MAX</span><span class="token token" style="color: rgb(57, 173, 181);">(</span><span>post_date::</span><span class="token token" style="color: rgb(124, 77, 255);">date</span><span class="token token" style="color: rgb(57, 173, 181);">)</span><span class="token token" style="color: rgb(57, 173, 181);">-</span><span> </span><span class="token token" style="color: rgb(124, 77, 255);">MIN</span><span class="token token" style="color: rgb(57, 173, 181);">(</span><span>post_date::</span><span class="token token" style="color: rgb(124, 77, 255);">date</span><span class="token token" style="color: rgb(57, 173, 181);">)</span><span> </span><span class="token token" style="color: rgb(124, 77, 255);">AS</span><span> days_between
</span><span></span><span class="token token" style="color: rgb(124, 77, 255);">FROM</span><span>
</span>	posts
<span></span><span class="token token" style="color: rgb(124, 77, 255);">WHERE</span><span>
</span><span>	DATE_PART</span><span class="token token" style="color: rgb(57, 173, 181);">(</span><span class="token token" style="color: rgb(246, 164, 52);">'year'</span><span class="token token" style="color: rgb(57, 173, 181);">,</span><span>post_date::</span><span class="token token" style="color: rgb(124, 77, 255);">date</span><span class="token token" style="color: rgb(57, 173, 181);">)</span><span class="token token" style="color: rgb(57, 173, 181);">=</span><span class="token token" style="color: rgb(247, 109, 71);">2021</span><span> 
</span><span></span><span class="token token" style="color: rgb(124, 77, 255);">GROUP</span><span> </span><span class="token token" style="color: rgb(124, 77, 255);">BY</span><span> 
</span>	user_id
<span>CLAUSE </span><span class="token token" style="color: rgb(170, 191, 201);">-- Replace CLAUSE with WHERE or HAVING</span><span>
</span><span>	</span><span class="token token" style="color: rgb(124, 77, 255);">COUNT</span><span class="token token" style="color: rgb(57, 173, 181);">(</span><span>post_id</span><span class="token token" style="color: rgb(57, 173, 181);">)</span><span class="token token" style="color: rgb(57, 173, 181);">&gt;</span><span class="token token" style="color: rgb(247, 109, 71);">1</span></code></div></pre></div></div></div></div><div tabindex="0" role="tabpanel" aria-labelledby="tabs-:R5lbj79f6:--tab-1" hidden="" id="tabs-:R5lbj79f6:--tabpanel-1" class="chakra-tabs__tab-panel css-15zvaxn"><h3 class="chakra-heading css-tscows">Solution</h3><div class="Markdown_reactMarkdown__X0aZ_"><p>First, we can use the <a target="_blank" rel="noopener noreferrer" href="https://datalemur.com/sql-tutorial/sql-aggregate-functions"><code>MIN()</code> and <code>MAX()</code> aggregate functions</a> on the <!-- --><code>post_date</code> column to retrieve the earliest and latest post dates, and substract one from another accordingly.</p>
<p>To calculate the difference for each user, we <!-- --><code>GROUP</code> the results by <!-- --><code>user_id</code>, and then filter for posts made in the year 2021. To do so, we use the <a target="_blank" rel="noopener noreferrer" href="https://datalemur.com/sql-tutorial/sql-date-time-function"><code>DATE_PART()</code> function</a> to extract the year from the <!-- --><code>post_date</code> column.</p>
<p>In the final step, to exclude users who have posted only once during the year, we apply the <a target="_blank" rel="noopener noreferrer" href="https://datalemur.com/sql-tutorial/sql-having"><code>HAVING</code> clause</a> with a <a target="_blank" rel="noopener noreferrer" href="https://datalemur.com/sql-tutorial/sql-aggregate-functions"><code>COUNT()</code></a> condition greater than 1.</p>
<pre><div style="text-align: left; white-space: pre; word-spacing: normal; word-break: normal; overflow-wrap: normal; color: rgb(144, 164, 174); background: rgb(250, 250, 250); font-family: &quot;Roboto Mono&quot;, monospace; font-size: 1em; line-height: 1.5em; tab-size: 4; hyphens: none; overflow: auto; position: relative; margin: 0.5em 0px; padding: 1.25em 1em;"><code style="white-space: pre; background: inherit;"><span class="token token" style="color: rgb(124, 77, 255);">SELECT</span><span> 
</span><span>	user_id</span><span class="token token" style="color: rgb(57, 173, 181);">,</span><span> 
</span><span>    </span><span class="token token" style="color: rgb(124, 77, 255);">MAX</span><span class="token token" style="color: rgb(57, 173, 181);">(</span><span>post_date::</span><span class="token token" style="color: rgb(124, 77, 255);">DATE</span><span class="token token" style="color: rgb(57, 173, 181);">)</span><span> </span><span class="token token" style="color: rgb(57, 173, 181);">-</span><span> </span><span class="token token" style="color: rgb(124, 77, 255);">MIN</span><span class="token token" style="color: rgb(57, 173, 181);">(</span><span>post_date::</span><span class="token token" style="color: rgb(124, 77, 255);">DATE</span><span class="token token" style="color: rgb(57, 173, 181);">)</span><span> </span><span class="token token" style="color: rgb(124, 77, 255);">AS</span><span> days_between
</span><span></span><span class="token token" style="color: rgb(124, 77, 255);">FROM</span><span> posts
</span><span></span><span class="token token" style="color: rgb(124, 77, 255);">WHERE</span><span> DATE_PART</span><span class="token token" style="color: rgb(57, 173, 181);">(</span><span class="token token" style="color: rgb(246, 164, 52);">'year'</span><span class="token token" style="color: rgb(57, 173, 181);">,</span><span> post_date::</span><span class="token token" style="color: rgb(124, 77, 255);">DATE</span><span class="token token" style="color: rgb(57, 173, 181);">)</span><span> </span><span class="token token" style="color: rgb(57, 173, 181);">=</span><span> </span><span class="token token" style="color: rgb(247, 109, 71);">2021</span><span> 
</span><span></span><span class="token token" style="color: rgb(124, 77, 255);">GROUP</span><span> </span><span class="token token" style="color: rgb(124, 77, 255);">BY</span><span> user_id
</span><span></span><span class="token token" style="color: rgb(124, 77, 255);">HAVING</span><span> </span><span class="token token" style="color: rgb(124, 77, 255);">COUNT</span><span class="token token" style="color: rgb(57, 173, 181);">(</span><span>post_id</span><span class="token token" style="color: rgb(57, 173, 181);">)</span><span class="token token" style="color: rgb(57, 173, 181);">&gt;</span><span class="token token" style="color: rgb(247, 109, 71);">1</span><span class="token token" style="color: rgb(57, 173, 181);">;</span></code></div></pre></div></div><div tabindex="0" role="tabpanel" aria-labelledby="tabs-:R5lbj79f6:--tab-2" hidden="" id="tabs-:R5lbj79f6:--tabpanel-2" class="chakra-tabs__tab-panel css-15zvaxn"><div class="css-lrvccz"><div class="css-134o37c"><div class="chakra-wrap css-ynkstv"><ul class="chakra-wrap__list css-19lo6pj"><div class="chakra-input__group css-vh9yad" data-group="true"><div class="chakra-input__left-element css-j2xror"><svg viewBox="0 0 16 14" focusable="false" class="chakra-icon css-8w3kun"><svg width="16" height="14" viewBox="0 0 16 14" fill="none" xmlns="http://www.w3.org/2000/svg"><path d="M1.5 7.50667C1.5 8.57333 2.24867 9.50267 3.30467 9.658C4.01667 9.76267 4.73667 9.844 5.46333 9.90067C5.774 9.92533 6.05867 10.088 6.232 10.348L8 13L9.768 10.348C9.94133 10.088 10.226 9.92533 10.5367 9.90133C11.2633 9.844 11.9833 9.76267 12.6953 9.658C13.7513 9.50267 14.5 8.574 14.5 7.506V3.494C14.5 2.426 13.7513 1.49733 12.6953 1.342C11.1406 1.11381 9.57135 0.999507 8 1C6.40533 1 4.83733 1.11667 3.30467 1.342C2.24867 1.49733 1.5 2.42667 1.5 3.494V7.506V7.50667Z" stroke="currentColor" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"></path></svg></svg></div><input placeholder="Add a comment" class="chakra-input css-1gui0l9"></div></ul></div><div class="css-iuz4m4"><p class="chakra-text css-1xqzysv">Sort:</p><button type="button" class="chakra-button chakra-menu__menu-button css-105zkyi" id="menu-button-:r2:" aria-expan