</span><span></span><span class="token token" style="color: rgb(124, 77, 255);">SELECT</span><span> user_id</span><span class="token token" style="color: rgb(57, 173, 181);">,</span><span> EXTRACT</span><span class="token token" style="color: rgb(57, 173, 181);">(</span><span class="token token" style="color: rgb(124, 77, 255);">DAY</span><span> </span><span class="token token" style="color: rgb(124, 77, 255);">FROM</span><span> </span><span class="token token" style="color: rgb(57, 173, 181);">(</span><span class="token token" style="color: rgb(124, 77, 255);">MAX</span><span class="token token" style="color: rgb(57, 173, 181);">(</span><span>post_date</span><span class="token token" style="color: rgb(57, 173, 181);">)</span><span> </span><span class="token token" style="color: rgb(57, 173, 181);">-</span><span> </span><span class="token token" style="color: rgb(124, 77, 255);">MIN</span><span class="token token" style="color: rgb(57, 173, 181);">(</span><span>post_date</span><span class="token token" style="color: rgb(57, 173, 181);">)</span><span class="token token" style="color: rgb(57, 173, 181);">)</span><span class="token token" style="color: rgb(57, 173, 181);">)</span><span> </span><span class="token token" style="color: rgb(124, 77, 255);">AS</span><span> </span><span class="token token" style="color: rgb(246, 164, 52);">"days_between"</span><span>
</span><span></span><span class="token token" style="color: rgb(124, 77, 255);">FROM</span><span> posts
</span><span></span><span class="token token" style="color: rgb(124, 77, 255);">WHERE</span><span> post_date </span><span class="token token" style="color: rgb(57, 173, 181);">BETWEEN</span><span> </span><span class="token token" style="color: rgb(246, 164, 52);">'2021-01-01'</span><span> </span><span class="token token" style="color: rgb(57, 173, 181);">AND</span><span> </span><span class="token token" style="color: rgb(246, 164, 52);">'2021-12-31'</span><span>
</span><span></span><span class="token token" style="color: rgb(124, 77, 255);">GROUP</span><span> </span><span class="token token" style="color: rgb(124, 77, 255);">BY</span><span> user_id
</span><span></span><span class="token token" style="color: rgb(124, 77, 255);">HAVING</span><span> </span><span class="token token" style="color: rgb(124, 77, 255);">count</span><span class="token token" style="color: rgb(57, 173, 181);">(</span><span>post_id</span><span class="token token" style="color: rgb(57, 173, 181);">)</span><span> </span><span class="token token" style="color: rgb(57, 173, 181);">&gt;</span><span> </span><span class="token token" style="color: rgb(247, 109, 71);">1</span><span class="token token" style="color: rgb(57, 173, 181);">;</span><span>
</span>
