<p>FROM (</p>
<p>SELECT user_id, MIN(DATE(post_date)) AS first_post,
MAX(DATE(post_date)) AS last_post</p>
<p>FROM posts</p>
<p>WHERE EXTRACT(YEAR FROM post_date) = 2021</p>
<p>GROUP BY user_id</p>
<p>HAVING COUNT(post_id) &gt;= 2</p>
<p>) AS tm</p>
